import 'react-native-gesture-handler';
import React, { useReducer, useEffect, useMemo, createContext, useContext } from 'react';
import { View, ActivityIndicator, Text, Button, TextInput, StyleSheet } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// --- 1. Constants and Utility Functions (AuthService Simulation) ---
const USER_TOKEN_KEY = 'userToken';
const USER_DATA_KEY = 'userData';

// A simple service to simulate API calls and AsyncStorage operations
const AuthService = {
  // Simulates a login API call
  async login(username, password) {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        if (username === 'test' && password === 'password') {
          const userToken = 'dummy-auth-token-123';
          const userData = { id: '1', name: 'Test User', email: 'test@example.com' };
          resolve({ userToken, userData });
        } else {
          reject(new Error('Invalid credentials'));
        }
      }, 1500); // Simulate network delay
    });
  },

  // Stores token and user data in AsyncStorage
  async storeUserData(userToken, userData) {
    await AsyncStorage.setItem(USER_TOKEN_KEY, userToken);
    await AsyncStorage.setItem(USER_DATA_KEY, JSON.stringify(userData));
  },

  // Retrieves token from AsyncStorage
  async getToken() {
    return await AsyncStorage.getItem(USER_TOKEN_KEY);
  },

  // Retrieves user data from AsyncStorage
  async getUser() {
    const userDataJson = await AsyncStorage.getItem(USER_DATA_KEY);
    return userDataJson ? JSON.parse(userDataJson) : null;
  },

  // Clears token and user data from AsyncStorage
  async logout() {
    await AsyncStorage.removeItem(USER_TOKEN_KEY);
    await AsyncStorage.removeItem(USER_DATA_KEY);
  },
};

// --- 2. AuthContext for Global State Management ---
export const AuthContext = createContext();

const authReducer = (prevState, action) => {
  switch (action.type) {
    case 'RESTORE_TOKEN':
      return {
        ...prevState,
        userToken: action.token,
        user: action.user,
        isLoading: false,
      };
    case 'SIGN_IN':
      return {
        ...prevState,
        isSignout: false,
        userToken: action.token,
        user: action.user,
      };
    case 'SIGN_OUT':
      return {
        ...prevState,
        isSignout: true,
        userToken: null,
        user: null,
      };
  }
};

export const AuthProvider = ({ children }) => {
  const [state, dispatch] = useReducer(authReducer, {
    isLoading: true,
    isSignout: false,
    userToken: null,
    user: null,
  });

  useEffect(() => {
    // Fetch the token and user data from storage then navigate to appropriate route
    const bootstrapAsync = async () => {
      let userToken;
      let user;
      try {
        userToken = await AuthService.getToken();
        user = await AuthService.getUser();
      } catch (e) {
        // Restoring token failed
        console.error('Failed to restore token or user data', e);
      }
      dispatch({ type: 'RESTORE_TOKEN', token: userToken, user: user });
    };

    bootstrapAsync();
  }, []);

  const authContext = useMemo(
    () => ({
      signIn: async (username, password) => {
        try {
          const { userToken, userData } = await AuthService.login(username, password);
          await AuthService.storeUserData(userToken, userData);
          dispatch({ type: 'SIGN_IN', token: userToken, user: userData });
        } catch (error) {
          console.error('Login failed', error);
          alert(error.message); // Show error to the user
        }
      },
      signOut: async () => {
        await AuthService.logout();
        dispatch({ type: 'SIGN_OUT' });
      },
      state: state, // Expose the current state for direct access
    }),
    [state]
  );

  return (
    <AuthContext.Provider value={authContext}>
      {children}
    </AuthContext.Provider>
  );
};

// --- 3. Screens ---

// Auth/Login Screen
function AuthScreen() {
  const [username, setUsername] = React.useState('');
  const [password, setPassword] = React.useState('');
  const { signIn } = useContext(AuthContext);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Login</Text>
      <TextInput
        placeholder="Username"
        value={username}
        onChangeText={setUsername}
        style={styles.input}
        autoCapitalize="none"
      />
      <TextInput
        placeholder="Password"
        value={password}
        onChangeText={setPassword}
        secureTextEntry
        style={styles.input}
      />
      <Button title="Sign in" onPress={() => signIn(username, password)} />
    </View>
  );
}

// Home/Main App Screen
function HomeScreen() {
  const { signOut, state } = useContext(AuthContext);
  const { user } = state;

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome {user ? user.name : 'User'}!</Text>
      <Text style={styles.subtitle}>You are logged in.</Text>
      <Button title="Sign Out" onPress={signOut} />
    </View>
  );
}

// Loading Screen
function SplashScreen() {
  return (
    <View style={styles.container}>
      <ActivityIndicator size="large" />
      <Text style={styles.loadingText}>Loading...</Text>
    </View>
  );
}

// --- 4. Navigation Stacks ---
const AuthStack = createStackNavigator();
function AuthNavigator() {
  return (
    <AuthStack.Navigator screenOptions={{ headerShown: false }}>
      <AuthStack.Screen name="SignIn" component={AuthScreen} />
    </AuthStack.Navigator>
  );
}

const AppStack = createStackNavigator();
function AppNavigator() {
  return (
    <AppStack.Navigator screenOptions={{ headerShown: false }}>
      <AppStack.Screen name="Home" component={HomeScreen} />
    </AppStack.Navigator>
  );
}

// --- 5. Main App Component ---
export default function App() {
  return (
    <AuthProvider>
      <RootNavigator />
    </AuthProvider>
  );
}

function RootNavigator() {
  const { state } = useContext(AuthContext);

  if (state.isLoading) {
    // We haven't finished checking for the token yet
    return <SplashScreen />;
  }

  return (
    <NavigationContainer>
      {state.userToken == null ? (
        // No token found, user isn't signed in
        <AuthNavigator />
      ) : (
        // User is signed in
        <AppNavigator />
      )}
    </NavigationContainer>
  );
}

